import '@testing-library/jest-dom';
import * as React from 'react';
import { render, screen } from '@testing-library/react';
// Using Jest's global describe, it, expect; no imports needed
import { Badge } from './Badge';

describe('Badge', () => {
  it('renders label', () => {
    render(<Badge label="Hello" />);
    expect(screen.getByText('Hello')).toBeInTheDocument();
  });

  it('renders icon slot', () => {
    render(<Badge label="Hi" icon={<span data-testid="icon">⭐</span>} />);
    expect(screen.getByTestId('icon')).toBeInTheDocument();
  });

  it('applies variant class', () => {
    render(<Badge label="Blue" variant="blue" />);
    const badgeRoot = screen.getByText('Blue').closest('span.inline-flex') as HTMLElement;
    expect(badgeRoot).toHaveClass('bg-gradient-blue');
  });
});
